import { useState, useRef, useEffect } from "react";

const DEFAULT_PHOTO = "data:image/jpeg;base64,";

const MOCK_FRIENDS = [
  { id: 1, name: "Sofia M.", handle: "@sofiam", emoji: "🍝", note: "Just loved Osteria Francescana" },
  { id: 2, name: "Jake R.", handle: "@jaker", emoji: "🍣", note: "Added 3 spots in Tokyo" },
  { id: 3, name: "Priya K.", handle: "@priyak", emoji: "🥘", note: "Visiting Barcelona next month" },
  { id: 4, name: "Theo L.", handle: "@theol", emoji: "🍷", note: "Just visited Le Bernardin" },
];

export default function Profile({ onPhotoChange }) {
  const [photo, setPhoto] = useState(() => {
    return localStorage.getItem("cooked_profile_photo") || DEFAULT_PHOTO;
  });
  const [name, setName] = useState(() => localStorage.getItem("cooked_profile_name") || "Luga");
  const [username, setUsername] = useState(() => localStorage.getItem("cooked_profile_username") || "@lugapodesta");
  const [editing, setEditing] = useState(false);
  const [editName, setEditName] = useState(name);
  const [editUsername, setEditUsername] = useState(username);
  const [activeTab, setActiveTab] = useState("favorites");
  const fileRef = useRef();

  // Stats derived from heat data
  const heat = JSON.parse(localStorage.getItem("cooked_heat") || '{"loved":[],"noped":[],"skipped":[]}');
  const loved = heat.loved || [];
  const noped = heat.noped || [];
  const restaurants = JSON.parse(localStorage.getItem("cooked_restaurants") || "[]");

  const lovedRestaurants = restaurants.filter(r => loved.includes(r.id)).slice(0, 6);
  const watchlist = restaurants.filter(r => {
    const lists = JSON.parse(localStorage.getItem("cooked_lists") || "{}");
    return lists.watchlist?.includes(r.id);
  }).slice(0, 6);

  const cities = [...new Set(lovedRestaurants.map(r => r.city))];

  // Save photo to localStorage and notify nav
  const handlePhotoUpload = (e) => {
    const file = e.target.files[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (ev) => {
      const dataUrl = ev.target.result;
      setPhoto(dataUrl);
      localStorage.setItem("cooked_profile_photo", dataUrl);
      if (onPhotoChange) onPhotoChange(dataUrl);
    };
    reader.readAsDataURL(file);
  };

  const saveEdit = () => {
    setName(editName);
    setUsername(editUsername);
    localStorage.setItem("cooked_profile_name", editName);
    localStorage.setItem("cooked_profile_username", editUsername);
    setEditing(false);
  };

  // Seed photo on first load if not set
  useEffect(() => {
    if (!localStorage.getItem("cooked_profile_photo")) {
      localStorage.setItem("cooked_profile_photo", DEFAULT_PHOTO);
      if (onPhotoChange) onPhotoChange(DEFAULT_PHOTO);
    }
  }, []);

  const tabs = [
    { key: "favorites", label: "Favorites" },
    { key: "targets", label: "Target List" },
    { key: "finds", label: "Finds" },
    { key: "feed", label: "Friends" },
  ];

  return (
    <div style={{
      minHeight: "100vh",
      background: "#faf6f0",
      fontFamily: "'DM Sans', sans-serif",
      paddingBottom: 100,
    }}>
      {/* Header band */}
      <div style={{
        background: "linear-gradient(160deg, #1e1208 0%, #3a1f0d 60%, #c4603a 100%)",
        padding: "48px 24px 80px",
        position: "relative",
        overflow: "hidden",
      }}>
        {/* Grain texture overlay */}
        <div style={{
          position: "absolute", inset: 0, opacity: 0.06,
          backgroundImage: "url(\"data:image/svg+xml,%3Csvg viewBox=%270 0 200 200%27 xmlns=%27http://www.w3.org/2000/svg%27%3E%3Cfilter id=%27n%27%3E%3CfeTurbulence type=%27fractalNoise%27 baseFrequency=%270.9%27 numOctaves=%274%27/%3E%3C/filter%3E%3Crect width=%27100%25%27 height=%27100%25%27 filter=%27url(%23n)%27/%3E%3C/svg%3E\")",
          backgroundSize: "200px",
        }} />

        {/* Edit button */}
        <button
          onClick={() => { setEditing(true); setEditName(name); setEditUsername(username); }}
          style={{
            position: "absolute", top: 16, right: 16,
            background: "rgba(255,255,255,0.12)", border: "1px solid rgba(255,255,255,0.2)",
            color: "#fff", borderRadius: 20, padding: "6px 14px",
            fontSize: 12, fontFamily: "'DM Mono', monospace", cursor: "pointer",
            letterSpacing: "0.05em",
          }}
        >EDIT</button>

        {/* Avatar */}
        <div style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: 12 }}>
          <div
            onClick={() => fileRef.current?.click()}
            style={{
              width: 96, height: 96, borderRadius: "50%",
              border: "3px solid #c4603a",
              boxShadow: "0 0 0 3px rgba(196,96,58,0.3), 0 8px 32px rgba(0,0,0,0.4)",
              overflow: "hidden", cursor: "pointer", position: "relative",
              flexShrink: 0,
            }}
          >
            <img src={photo} alt="profile" style={{ width: "100%", height: "100%", objectFit: "cover" }} />

          </div>
          <input ref={fileRef} type="file" accept="image/*" style={{ display: "none" }} onChange={handlePhotoUpload} />

          <div style={{ textAlign: "center" }}>
            <div style={{
              fontFamily: "'Cormorant Garamond', serif",
              fontSize: 28, fontWeight: 600, color: "#fff",
              letterSpacing: "-0.01em", lineHeight: 1.1,
            }}>{name}</div>
            <div style={{
              fontFamily: "'DM Mono', monospace", fontSize: 12,
              color: "rgba(255,255,255,0.5)", marginTop: 2, letterSpacing: "0.05em",
            }}>{username}</div>
          </div>
        </div>
      </div>

      {/* Stats card — overlaps header */}
      <div style={{
        margin: "0 16px",
        marginTop: -40,
        background: "#fff9f2",
        border: "1px solid #ddd0bc",
        borderRadius: 16,
        padding: "20px 0 12px",
        display: "flex",
        boxShadow: "0 4px 24px rgba(30,18,8,0.08)",
        position: "relative", zIndex: 2,
      }}>
        {[
          { val: "248", label: "Followers" },
          { val: "91", label: "Following" },
          { val: cities.length, label: "Cities" },
          { val: loved.length || "0", label: "Loved" },
        ].map((s, i, arr) => (
          <div key={s.label} style={{
            flex: 1, textAlign: "center",
            borderRight: i < arr.length - 1 ? "1px solid #ede4d3" : "none",
          }}>
            <div style={{
              fontFamily: "'Cormorant Garamond', serif",
              fontSize: 26, fontWeight: 700, color: "#1e1208", lineHeight: 1,
            }}>{s.val}</div>
            <div style={{
              fontFamily: "'DM Mono', monospace", fontSize: 10,
              color: "#8a7060", marginTop: 4, letterSpacing: "0.06em",
              textTransform: "uppercase",
            }}>{s.label}</div>
          </div>
        ))}
      </div>

      {/* Tab bar */}
      <div style={{
        display: "flex", overflowX: "auto", padding: "16px 16px 0",
        gap: 8, scrollbarWidth: "none",
      }}>
        {tabs.map(t => (
          <button key={t.key} onClick={() => setActiveTab(t.key)} style={{
            flexShrink: 0,
            padding: "8px 16px", borderRadius: 20,
            border: activeTab === t.key ? "none" : "1px solid #ddd0bc",
            background: activeTab === t.key ? "#c4603a" : "transparent",
            color: activeTab === t.key ? "#fff" : "#8a7060",
            fontFamily: "'DM Mono', monospace", fontSize: 11,
            letterSpacing: "0.05em", cursor: "pointer",
            textTransform: "uppercase",
          }}>{t.label}</button>
        ))}
      </div>

      {/* Tab content */}
      <div style={{ padding: "16px 16px 0" }}>
        {activeTab === "favorites" && (
          <Section
            title="❤ Favorites"
            items={lovedRestaurants}
            empty="Swipe right on restaurants in Heat to build your favorites"
            emptyIcon="🔥"
          />
        )}
        {activeTab === "targets" && (
          <Section
            title="◎ Target List"
            items={watchlist}
            empty="Add restaurants to your watchlist to see them here"
            emptyIcon="🎯"
          />
        )}
        {activeTab === "finds" && (
          <Section
            title="✓ Regular Spots"
            items={[]}
            empty="Mark restaurants as visited to track your regulars"
            emptyIcon="📍"
          />
        )}
        {activeTab === "feed" && (
          <FriendFeed friends={MOCK_FRIENDS} />
        )}
      </div>

      {/* Share button */}
      <div style={{ padding: "24px 16px 0" }}>
        <button style={{
          width: "100%", padding: "14px",
          background: "transparent",
          border: "1px solid #c4603a",
          borderRadius: 12, color: "#c4603a",
          fontFamily: "'DM Mono', monospace", fontSize: 12,
          letterSpacing: "0.08em", cursor: "pointer",
          textTransform: "uppercase",
        }}>
          ↗ Share Profile
        </button>
      </div>

      {/* Backup buttons */}
      <div style={{ padding: "12px 16px 0", display: "flex", gap: 10 }}>
        <button
          onClick={() => {
            const keys = [
              "cooked_restaurants", "cooked_photos", "cooked_photo_resolved",
              "cooked_heat", "cooked_hidden", "cooked_watchlist", "cooked_finds",
              "cooked_profile_photo", "cooked_profile_name", "cooked_profile_username",
              "cooked_data_version",
            ];
            const backup = {};
            keys.forEach(k => { const v = localStorage.getItem(k); if (v) backup[k] = v; });
            const blob = new Blob([JSON.stringify(backup)], { type: "application/json" });
            const url = URL.createObjectURL(blob);
            const a = document.createElement("a");
            a.href = url;
            a.download = `cooked_backup_${new Date().toISOString().slice(0,10)}.json`;
            a.click();
            URL.revokeObjectURL(url);
          }}
          style={{
            flex: 1, padding: "12px",
            background: "transparent",
            border: "1px solid #ddd0bc",
            borderRadius: 12, color: "#8a7060",
            fontFamily: "'DM Mono', monospace", fontSize: 11,
            letterSpacing: "0.08em", cursor: "pointer",
            textTransform: "uppercase",
          }}
        >
          ↓ Export Backup
        </button>
        <button
          onClick={() => {
            const input = document.createElement("input");
            input.type = "file";
            input.accept = ".json";
            input.onchange = (e) => {
              const file = e.target.files[0];
              if (!file) return;
              const reader = new FileReader();
              reader.onload = (ev) => {
                try {
                  const data = JSON.parse(ev.target.result);
                  Object.entries(data).forEach(([k, v]) => localStorage.setItem(k, v));
                  alert("Backup restored! Reloading…");
                  window.location.reload();
                } catch {
                  alert("Invalid backup file.");
                }
              };
              reader.readAsText(file);
            };
            input.click();
          }}
          style={{
            flex: 1, padding: "12px",
            background: "transparent",
            border: "1px solid #ddd0bc",
            borderRadius: 12, color: "#8a7060",
            fontFamily: "'DM Mono', monospace", fontSize: 11,
            letterSpacing: "0.08em", cursor: "pointer",
            textTransform: "uppercase",
          }}
        >
          ↑ Import Backup
        </button>
      </div>

      {/* Edit modal */}
      {editing && (
        <div style={{
          position: "fixed", inset: 0, background: "rgba(30,18,8,0.6)",
          display: "flex", alignItems: "flex-end", justifyContent: "center",
          zIndex: 100, backdropFilter: "blur(4px)",
        }} onClick={() => setEditing(false)}>
          <div onClick={e => e.stopPropagation()} style={{
            background: "#faf6f0", borderRadius: "20px 20px 0 0",
            padding: "28px 24px 40px", width: "100%", maxWidth: 480,
          }}>
            <div style={{
              fontFamily: "'Cormorant Garamond', serif",
              fontSize: 22, fontWeight: 600, marginBottom: 20, color: "#1e1208",
            }}>Edit Profile</div>
            {[
              { label: "Name", val: editName, set: setEditName },
              { label: "Username", val: editUsername, set: setEditUsername },
            ].map(f => (
              <div key={f.label} style={{ marginBottom: 16 }}>
                <div style={{ fontFamily: "'DM Mono', monospace", fontSize: 10, color: "#8a7060", marginBottom: 6, letterSpacing: "0.06em", textTransform: "uppercase" }}>{f.label}</div>
                <input
                  value={f.val}
                  onChange={e => f.set(e.target.value)}
                  style={{
                    width: "100%", padding: "12px 14px",
                    border: "1px solid #ddd0bc", borderRadius: 10,
                    fontFamily: "'DM Sans', sans-serif", fontSize: 15,
                    background: "#fff9f2", color: "#1e1208",
                    boxSizing: "border-box", outline: "none",
                  }}
                />
              </div>
            ))}
            <button onClick={saveEdit} style={{
              width: "100%", padding: 14, background: "#c4603a",
              border: "none", borderRadius: 12, color: "#fff",
              fontFamily: "'DM Mono', monospace", fontSize: 12,
              letterSpacing: "0.08em", cursor: "pointer",
              textTransform: "uppercase", marginTop: 4,
            }}>Save</button>
          </div>
        </div>
      )}
    </div>
  );
}

function Section({ title, items, empty, emptyIcon }) {
  if (!items.length) return (
    <div style={{
      textAlign: "center", padding: "40px 20px",
      color: "#8a7060", fontFamily: "'DM Sans', sans-serif",
    }}>
      <div style={{ fontSize: 36, marginBottom: 12 }}>{emptyIcon}</div>
      <div style={{ fontSize: 14, lineHeight: 1.5 }}>{empty}</div>
    </div>
  );

  return (
    <div>
      <div style={{
        fontFamily: "'DM Mono', monospace", fontSize: 11,
        color: "#8a7060", letterSpacing: "0.08em",
        textTransform: "uppercase", marginBottom: 12,
      }}>{title}</div>
      <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
        {items.map(r => (
          <div key={r.id} style={{
            background: "#fff9f2", border: "1px solid #ede4d3",
            borderRadius: 12, padding: "12px 14px",
            display: "flex", alignItems: "center", gap: 12,
          }}>
            <div style={{
              width: 44, height: 44, borderRadius: 10, overflow: "hidden",
              flexShrink: 0, background: "#ede4d3",
            }}>
              {r.img && <img src={r.img} alt={r.name} style={{ width: "100%", height: "100%", objectFit: "cover" }} />}
            </div>
            <div style={{ flex: 1, minWidth: 0 }}>
              <div style={{
                fontFamily: "'Cormorant Garamond', serif",
                fontSize: 17, fontWeight: 600, color: "#1e1208",
                whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis",
              }}>{r.name}</div>
              <div style={{
                fontFamily: "'DM Mono', monospace", fontSize: 10,
                color: "#8a7060", marginTop: 2, letterSpacing: "0.04em",
              }}>{r.city} · {r.cuisine}</div>
            </div>
            <div style={{ fontSize: 16, flexShrink: 0 }}>
              {"🔥".repeat(r.heat || 3)}
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

function FriendFeed({ friends }) {
  return (
    <div>
      <div style={{
        fontFamily: "'DM Mono', monospace", fontSize: 11,
        color: "#8a7060", letterSpacing: "0.08em",
        textTransform: "uppercase", marginBottom: 12,
      }}>Friends Activity</div>
      <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
        {friends.map(f => (
          <div key={f.id} style={{
            background: "#fff9f2", border: "1px solid #ede4d3",
            borderRadius: 12, padding: "12px 14px",
            display: "flex", alignItems: "center", gap: 12,
          }}>
            <div style={{
              width: 44, height: 44, borderRadius: "50%",
              background: "#ede4d3", display: "flex",
              alignItems: "center", justifyContent: "center",
              fontSize: 22, flexShrink: 0,
            }}>{f.emoji}</div>
            <div style={{ flex: 1 }}>
              <div style={{
                display: "flex", alignItems: "baseline", gap: 6,
              }}>
                <span style={{ fontFamily: "'Cormorant Garamond', serif", fontSize: 17, fontWeight: 600, color: "#1e1208" }}>{f.name}</span>
                <span style={{ fontFamily: "'DM Mono', monospace", fontSize: 10, color: "#8a7060" }}>{f.handle}</span>
              </div>
              <div style={{ fontFamily: "'DM Sans', sans-serif", fontSize: 13, color: "#8a7060", marginTop: 2 }}>{f.note}</div>
            </div>
          </div>
        ))}
      </div>
      <div style={{
        textAlign: "center", padding: "24px 0",
        fontFamily: "'DM Mono', monospace", fontSize: 10,
        color: "#ddd0bc", letterSpacing: "0.06em",
      }}>FRIEND ACTIVITY COMING SOON</div>
    </div>
  );
}
